9	pub fn test_tree_sanity(tree: &BOSTree) {
10	    // Count nodes by traversing using select(0) and next_node().
11	    let mut count = 0;
12	    let mut current = tree.bostree_select(0);
13	    while let Some(node) = current {
14	        count += 1;
15	        current = bostree_next_node(&node);
16	    }
17	    let reported_count = tree.bostree_node_count();
18	    if count != reported_count {
19	        println!(
20	            "Manual node count yielded {}, order statistics reported {}",
21	            count, reported_count
22	        );
23	        panic!("Exiting due to errors.");
24	    }
25	    // For each in-order index, check various invariants.
26	    for i in 0..reported_count {
27	        let node_opt = tree.bostree_select(i);
28	        if node_opt.is_none() {
29	            println!(
30	                "Rank {} node not found, though count is {}",
31	                i, reported_count
32	            );
33	            panic!("Exiting due to errors.");
34	        }
35	        let node = node_opt.unwrap();
36	        let rank = bostree_rank(&node);
37	        if rank != i {
38	            println!(
39	                "Rank for node {} is {} but should be {}",
40	                node.borrow().key,
41	                rank,
42	                i
43	            );
44	            panic!("Exiting due to errors.");
45	        }
46	        let lookup_node = tree.bostree_lookup(&node.borrow().key);
47	        if let Some(ln) = lookup_node {
48	            if !Rc::ptr_eq(&node, &ln) {
49	                println!("Lookup for {} returned the wrong node.", node.borrow().key);
50	                panic!("Exiting due to errors.");
51	            }
52	        } else {
53	            println!("Lookup for {} returned None.", node.borrow().key);
54	            panic!("Exiting due to errors.");
55	        }
56	        let next_node = bostree_next_node(&node);
57	        let select_next = tree.bostree_select(i + 1);
58	        match (next_node, select_next) {
59	            (Some(n1), Some(n2)) => {
60	                if !Rc::ptr_eq(&n1, &n2) {
61	                    println!(
62	                        "Next node is {}, but select(i+1) is {}",
63	                        n1.borrow().key,
64	                        n2.borrow().key
65	                    );
66	                    panic!("Exiting due to errors.");
67	                }
68	            }
69	            (None, None) => {}
70	            _ => {
71	                println!("Mismatch between next node and select(i+1) for index {}", i);
72	                panic!("Exiting due to errors.");
73	            }
74	        }
75	        let prev_node = if i == 0 {
76	            None
77	        } else {
78	            tree.bostree_select(i - 1)
79	        };
80	        let node_prev = bostree_previous_node(&node);
81	        match (prev_node, node_prev) {
82	            (Some(n1), Some(n2)) => {
83	                if !Rc::ptr_eq(&n1, &n2) {
84	                    println!(
85	                        "Previous node is {}, but select(i-1) is {}",
86	                        n2.borrow().key,
87	                        n1.borrow().key
88	                    );
89	                    panic!("Exiting due to errors.");
90	                }
91	            }
92	            (None, None) => {}
93	            _ => {
94	                println!(
95	                    "Mismatch between previous node and select(i-1) for index {}",
96	                    i
97	                );
98	                panic!("Exiting due to errors.");
99	            }
100	        }
101	        // Check that if a node has a parent then it is one of its children.
102	        if let Some(ref parent_weak) = node.borrow().parent_node {
103	            if let Some(parent) = parent_weak.upgrade() {
104	                let left_ok = parent
105	                    .borrow()
106	                    .left_child_node
107	                    .as_ref()
108	                    .map_or(false, |left| Rc::ptr_eq(&node, left));
109	                let right_ok = parent
110	                    .borrow()
111	                    .right_child_node
112	                    .as_ref()
113	                    .map_or(false, |right| Rc::ptr_eq(&node, right));
114	                if !left_ok && !right_ok {
115	                    println!(
116	                        "Node {} has a parent, {}, but is not one of its children.",
117	                        node.borrow().key,
118	                        parent.borrow().key
119	                    );
120	                    panic!("Exiting due to errors.");
121	                }
122	            }
123	        }
124	        // Recursive functions to compute actual depth and count.
125	        fn actual_depth(node: &Rc<RefCell<BOSNode>>) -> u32 {
126	            let left_depth = node
127	                .borrow()
128	                .left_child_node
129	                .as_ref()
130	                .map_or(0, |left| actual_depth(left) + 1);
131	            let right_depth = node
132	                .borrow()
133	                .right_child_node
134	                .as_ref()
135	                .map_or(0, |right| actual_depth(right) + 1);
136	            max(left_depth, right_depth)
137	        }
138	        fn actual_count(node: &Rc<RefCell<BOSNode>>) -> u32 {
139	            let left_count = node
140	                .borrow()
141	                .left_child_node
142	                .as_ref()
143	                .map_or(0, |left| actual_count(left));
144	            let right_count = node
145	                .borrow()
146	                .right_child_node
147	                .as_ref()
148	                .map_or(0, |right| actual_count(right));
149	            left_count + right_count + 1
150	        }
151	        let actual_depth_val = actual_depth(&node);
152	        if actual_depth_val != node.borrow().depth {
153	            println!(
154	                "Node {} reports depth {} when the actual depth is {}",
155	                node.borrow().key,
156	                node.borrow().depth,
157	                actual_depth_val
158	            );
159	            panic!("Exiting due to errors.");
160	        }
161	        if let Some(ref left) = node.borrow().left_child_node {
162	            let left_count = actual_count(left);
163	            if left_count != node.borrow().left_child_count {
164	                println!(
165	                    "Node {} reports {} left children when there are {}",
166	                    node.borrow().key,
167	                    node.borrow().left_child_count,
168	                    left_count
169	                );
170	                panic!("Exiting due to errors.");
171	            }
172	        }
173	        if let Some(ref right) = node.borrow().right_child_node {
174	            let right_count = actual_count(right);
175	            if right_count != node.borrow().right_child_count {
176	                println!(
177	                    "Node {} reports {} right children when there are {}",
178	                    node.borrow().key,
179	                    node.borrow().right_child_count,
180	                    right_count
181	                );
182	                panic!("Exiting due to errors.");
183	            }
184	        }
185	        let left_depth = node
186	            .borrow()
187	            .left_child_node
188	            .as_ref()
189	            .map_or(0, |n| n.borrow().depth + 1);
190	        let right_depth = node
191	            .borrow()
192	            .right_child_node
193	            .as_ref()
194	            .map_or(0, |n| n.borrow().depth + 1);
195	        if (left_depth as i32 - right_depth as i32).abs() > 1 {
196	            println!(
197	                "Node {} violates the balance constraint: {} left depth vs. {} right depth",
198	                node.borrow().key,
199	                left_depth,
200	                right_depth
201	            );
202	            panic!("Exiting due to errors.");
203	        }
204	    }
205	}
